class Solution:
    def stringHash(self, s, k):
        # Independent implementation summing ordinals via a comprehension
        # rather than an explicit accumulator loop.
        chars = []
        for i in range(0, len(s), k):
            chunk_sum = sum(ord(c) - 97 for c in s[i:i + k])
            chars.append(chr(97 + chunk_sum % 26))
        return ''.join(chars)

