class Solution:
    def stringHash(self, s, k):
        result = []
        for i in range(0, len(s), k):
            chunk = s[i:i + k]
            total = sum(ord(c) - ord('a') for c in chunk)
            result.append(chr(ord('a') + total % 26))
        return ''.join(result)

