var stringHash = function(s, k) {
    let result = '';
    for (let i = 0; i < s.length; i += k) {
        const chunk = s.slice(i, i + k);
        let total = 0;
        for (const c of chunk) total += c.charCodeAt(0) - 97;
        result += String.fromCharCode(97 + total % 26);
    }
    return result;
};
